var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"윽……","JPN":"うっ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"나오님…… 괜찮으십니까?","JPN":"ナオ様……大丈夫ですか？","ENG":"Miss Nao... Are you all right?","TWN":"奈緒大人……您沒事吧？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"난 아직 괜찮다만. 너는 별로 안 그래보이는구나?","JPN":"わしはまだ平気じゃが。お主はそうでもないようじゃのう。","ENG":"I'm good, but... you don't seem to be.","TWN":"我目前是沒事，但你看起來不像沒事欸？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……죄송합니다. 더는 몸이 움직이지 않는군요.","JPN":"……申し訳ございません。もう体が動かないようです。","ENG":"...My apologies. My body is refusing to listen to me.","TWN":"……抱歉，我的身體已經到達極限。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"됐다. 쉬고 있어라.","JPN":"もう良い。休んでいろ。","ENG":"Very well. Rest.","TWN":"算了，你休息吧！"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"어머, 아직도 덤비려고?","JPN":"あら、まだかかってくるつもり？","ENG":"Oh my, still not had enough?","TWN":"哇喔，你還要繼續嗎？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"네 녀석…… 일부러 급소만 피해서 찌르는 거지?","JPN":"貴様……わざわざ急所を外しているじゃろう？","ENG":"Why you...! You purposefully avoided stabbing us on our pressure points, didn't you?","TWN":"你這丫頭……是故意避開要害的吧？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아하하, 들켰어? 바로 머리부터 잘라버리면 발버둥치는 모습을 못 보는 걸.","JPN":"あはは、バレた？　最初に頭を切っちゃうと足掻く姿を見られないじゃない。","ENG":"Ahahaha! Was it that obvious? But if I cut your head off from the start, I can't see you two suffer.","TWN":"哈哈哈，被你發現啦？因為一刀就把頭砍下的話，就看不到拼命掙扎的好戲啦。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그리고 너……","JPN":"それにお前……","ENG":"And you...","TWN":"還有……"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"감히 내 공격을 막다니. 첫인상부터 아주 불쾌했다고.","JPN":"私の攻撃を止めるなんて。第一印象からしてとても不愉快だったのよ。","ENG":"You dare blocked my attack. I didn't like you from the very first time.","TWN":"你竟敢擋下我的攻擊，我對你的第一印象很差喔！"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"큭큭, 자기가 예견하지 못한 상황을 겪는 게 두렵냐?","JPN":"くくっ、自分が予言できなかった状況になるのが恐ろしいのか？","ENG":"Haha. Are you afraid something you didn't anticipate will happen?","TWN":"呵呵，你是怕發生你沒預料到的情況嗎？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"네 녀석…… 바람의 목소리가 없으면 그저 겁쟁이일 뿐이구나?","JPN":"貴様……風の声がなければただの臆病者じゃな？","ENG":"Without the voice of wind... You're just a coward, aren't you?","TWN":"你這丫頭……我看你沒有風聲的話，就只是個膽小鬼吧？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"呃……！"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그런 꼴로 할 말은 아닐 텐데?","JPN":"そんな格好でする話じゃないわね。","ENG":"It's not as convincing when it's coming out of your mouth right now, hmm?","TWN":"先看看你那副德性吧？還在那大言不慚！"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"너희가 따르는 원본도 나처럼 관측할 수 있는 힘이 있잖아?","JPN":"お前たちが従うオリジナルも私みたいに観測できる力があるでしょ？","ENG":"The Original you follow also has powers like mine, no?","TWN":"你們的正本不也和我一樣，有可以觀測的能力嗎？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"녀석이 너희 둘만으로 날 막을 수 있다고 판단한 거라면, 결국 내가 원본보다 더 우월하다는 의미 아니겠어?","JPN":"あいつがお前たち二人だけで私を止められると判断したのなら、結局私がオリジナルよりもっと優れてるって意味じゃないかしら。","ENG":"If she thought you two could stop me and I win, doesn't that mean that I'm the superior one?","TWN":"若她的判斷是單憑你們二個就能阻止我，那就表示我比正本還要卓越吧？"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"바람의 목소리를…… 만능이라고 착각마라. 네가 알고 싶어하는 사실만을 들려주는 것이니.","JPN":"風の声を……万能だと勘違いするでない。お前が知りたいと思っていることを聞かせてくれるだけじゃ。","ENG":"Don't mistake the voice of wind... for being a solution for all. It only allows you to hear what you want to know.","TWN":"你以為……風聲是無所不能的嗎？風聲只會說你想知道的事。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};